const month = new Date().getMonth() + 1;
const day = new Date().getDate();
const week = Math.ceil(day / 7);

// ── HTML email builder helpers ──
const FONT = "-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif";
const GREEN = '#2D5A27';
const GOLD = '#C5A55A';
const DARK = '#1a1a2e';

function headerBar() {
