}

function urgencyBanner(headline, subheadline, badgeText, badgeColor) {
  return '<tr><td style="background-color:' + (badgeColor || '#C0392B') + ';"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%"><tr><td align="center" style="padding:12px 24px;"><span style="font-family:' + FONT + '; font-size:12px; font-weight:700; color:#ffffff; text-transform:uppercase; letter-spacing:2px; background-color:rgba(0,0,0,0.2); padding:4px 12px; border-radius:4px;">' + badgeText + '</span></td></tr></table></td></tr><tr><td style="background: linear-gradient(135deg, #2D5A27 0%, #3d7a34 50%, #2D5A27 100%);"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%"><tr><td align="center" style="padding:40px 32px 16px;"><h1 style="margin:0; font-family:' + FONT + '; font-size:28px; font-weight:800; color:#ffffff; line-height:1.2;">' + headline + '</h1></td></tr><tr><td align="center" style="padding:8px 40px 40px;"><p style="margin:0; font-family:' + FONT + '; font-size:16px; color:' + GOLD + '; line-height:1.5; font-weight:500;">' + subheadline + '</p></td></tr></table></td></tr>';
}

function bodySection(html) {
  return '<tr><td style="padding:32px 32px 16px;"><div style="font-family:' + FONT + '; font-size:15px; color:#333333; line-height:1.7;">' + html + '</div></td></tr>';
}

function urgencyCountdown(label, display) {
  return '<tr><td style="padding:0 32px 24px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="border:2px solid #C0392B; border-radius:8px;"><tr><td align="center" style="padding:16px;"><p style="margin:0 0 4px; font-family:' + FONT + '; font-size:11px; color:#C0392B; text-transform:uppercase; letter-spacing:1.5px; font-weight:700;">' + label + '</p><p style="margin:0; font-family:' + FONT + '; font-size:20px; color:#1a1a1a; font-weight:800;">' + display + '</p></td></tr></table></td></tr>';
}

function benefitsBox(html) {
