// Determine which email to send based on schedule
// Feb week 1 = email 1, Feb week 3 = email 2, Mar week 1 = email 3, Mar week 3 = email 4
let emailIdx;
if (month === 2 && week <= 2) emailIdx = 0;
else if (month === 2) emailIdx = 1;
else if (month === 3 && week <= 2) emailIdx = 2;
else emailIdx = 3;

const template = campaignEmails[emailIdx];

// Build dedup set
const sentItems = $('Fetch Sent History').all().map(i => i.json);
const sentSet = new Set(sentItems.map(s => `${s.contact_email}|${s.email_type}`));

const results = [];
for (const item of $input.all()) {
  const c = item.json;
  if (!c.email) continue;
  const dedupKey = `${c.email}|${template.emailType}`;
  if (sentSet.has(dedupKey)) continue;

  const firstName = c.first_name || 'there';
  const city = c.city || 'Madison';
  const subject = template.subject.replace('{name}', firstName).replace('{{first_name}}', firstName).replace('{{city}}', city);
  const textBody = template.textBody.replace('{name}', firstName);

  // Build HTML
  let bannerHtml, bodyContentHtml;
  if (template.template === 'urgency') {
    bannerHtml = urgencyBanner(template.headline, template.subheadline, template.alertBadge, template.alertColor);
    bodyContentHtml = bodySection(template.stakesHtml) + urgencyCountdown(template.urgencyLabel, template.urgencyDisplay) + benefitsBox(template.benefitsHtml);
  } else {
    bannerHtml = heroBanner(template.headline.replace('{{city}}', city), template.subheadline);
    bodyContentHtml = bodySection(template.bodyHtml);
  }

  const htmlBody = buildHtml({
    previewText: template.previewText.replace('{{city}}', city),
    bannerHtml: bannerHtml,
    bodyHtml: bodyContentHtml,
    reviewHtml: reviewBlock(template.reviewText, template.reviewerName),
    ctaText: template.ctaText,
    ctaUrl: template.ctaUrl
  });

  results.push({ json: { ...c, subject, body: textBody, htmlBody, emailType: template.emailType } });
}
return results.length > 0 ? results : [{ json: { _skip: true } }];
